// MARK: - Models

enum TransactionType: String, Codable, CaseIterable {
    case deposit = "Deposit"
    case withdrawal = "Withdrawal"
    case transfer = "Transfer"
    case payment = "Payment"
}

enum TransactionStatus: String, Codable {
    case pending = "Pending"
    case completed = "Completed"
    case failed = "Failed"
    case cancelled = "Cancelled"
}

enum Currency: String, Codable {
    case usd = "USD"
    case eur = "EUR"
    case gbp = "GBP"
}

struct Transaction: Identifiable, Codable {
    let id: UUID
    let type: TransactionType
    let amount: Decimal
    let currency: Currency
    let sourceAccountId: String
    let destinationAccountId: String?
    let description: String
    let timestamp: Date
    var status: TransactionStatus
    let referenceNumber: String
    
    init(type: TransactionType, amount: Decimal, currency: Currency = .usd,
         sourceAccountId: String, destinationAccountId: String? = nil,
         description: String) {
        self.id = UUID()
        self.type = type
        self.amount = amount
        self.currency = currency
        self.sourceAccountId = sourceAccountId
        self.destinationAccountId = destinationAccountId
        self.description = description
        self.timestamp = Date()
        self.status = .pending
        self.referenceNumber = Self.generateReferenceNumber()
    }
    
    private static func generateReferenceNumber() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        let random = Int.random(in: 1000...9999)
        return "TXN-\(timestamp)-\(random)"
    }
}

struct BankAccount: Identifiable, Codable {
