// MARK: - Encryption Service

final class EncryptionService {
    
    static let shared = EncryptionService()
    
    private let keychainService = "com.bankingapp.encryption"
    private let symmetricKeyTag = "com.bankingapp.symmetrickey"
    
    private init() {
        _ = getOrCreateSymmetricKey()
    }
    
    // MARK: - Symmetric Key Management
    
    private func getOrCreateSymmetricKey() -> SymmetricKey {
        if let existingKeyData = loadKeyFromKeychain(tag: symmetricKeyTag) {
            return SymmetricKey(data: existingKeyData)
        }
        
        let newKey = SymmetricKey(size: .bits256)
        let keyData = newKey.withUnsafeBytes { Data($0) }
        saveKeyToKeychain(tag: symmetricKeyTag, keyData: keyData)
        return newKey
    }
    
    private func saveKeyToKeychain(tag: String, keyData: Data) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: tag,
            kSecValueData as String: keyData,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]
        
        SecItemDelete(query as CFDictionary)
        let status = SecItemAdd(query as CFDictionary, nil)
        
        if status != errSecSuccess {
            print("Failed to save key to keychain: \(status)")
        }
    }
    
    private func loadKeyFromKeychain(tag: String) -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: tag,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess else { return nil }
        return result as? Data
    }
    
    // MARK: - Encryption / Decryption
    
    func encrypt(data: Data) throws -> Data {
        let key = getOrCreateSymmetricKey()
        let sealedBox = try AES.GCM.seal(data, using: key)
        guard let combined = sealedBox.combined else {
            throw EncryptionError.encryptionFailed
        }
        return combined
    }
    
    func decrypt(data: Data) throws -> Data {
        let key = getOrCreateSymmetricKey()
        let sealedBox = try AES.GCM.SealedBox(combined: data)
        return try AES.GCM.open(sealedBox, using: key)
    }
    
    func encryptString(_ string: String) throws -> Data {
        guard let data = string.data(using: .utf8) else {
            throw EncryptionError.invalidInput
        }
        return try encrypt(data: data)
    }
    
    func decryptToString(data: Data) throws -> String {
        let decryptedData = try decrypt(data: data)
        guard let string = String(data: decryptedData, encoding: .utf8) else {
            throw EncryptionError.decryptionFailed
        }
        return string
    }
    
    func hashData(_ data: Data) -> String {
        let digest = SHA256.hash(data: data)
        return digest.compactMap { String(format: "%02x", $0) }.joined()
    }
    
    func encryptModel<T: Codable>(_ model: T) throws -> Data {
        let encoder = JSONEncoder()
        encoder.dateEncodingStrategy = .iso8601
        let jsonData = try encoder.encode(model)
        return try encrypt(data: jsonData)
    }
    
    func decryptModel<T: Codable>(_ data: Data, as type: T.Type) throws -> T {
        let decryptedData = try decrypt(data: data)
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(type, from: decryptedData)
    }
    
    enum EncryptionError: LocalizedError {
        case encryptionFailed
        case decryptionFailed
        case invalidInput
        case keyGenerationFailed
        
        var errorDescription: String? {
            switch self {
            case .encryptionFailed: return "Failed to encrypt data"
            case .decryptionFailed: return "Failed to decrypt data"
            case .invalidInput: return "Invalid input data"
            case .keyGenerationFailed: return "Failed to generate encryption key"
            }
        }
    }
}

// MARK: - Secure Storage

final class SecureStorage {
    
    static let shared = SecureStorage()
    private let encryption = EncryptionService.shared
    private let fileManager = FileManager.default
    
    private var storageURL: URL {
        let documentsPath = fileManager.urls(for: .documentDirectory, in: .userDomainMask)[0]
        let storageDir = documentsPath.appendingPathComponent("SecureBankData", isDirectory: true)
        
        if !fileManager.fileExists(atPath: storageDir.path) {
            try? fileManager.createDirectory(at: storageDir, withIntermediateDirectories: true)
        }
        return storageDir
    }
    
    private init() {}
    
    func save<T: Codable>(_ model: T, forKey key: String) throws {
        let encryptedData = try encryption.encryptModel(model)
        let fileURL = storageURL.appendingPathComponent(key)
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func load<T: Codable>(forKey key: String, as type: T.Type) throws -> T {
        let fileURL = storageURL.appendingPathComponent(key)
        let encryptedData = try Data(contentsOf: fileURL)
        return try encryption.decryptModel(encryptedData, as: type)
    }
    
    func delete(forKey key: String) throws {
        let fileURL = storageURL.appendingPathComponent(key)
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
        }
    }
    
    func exists(forKey key: String) -> Bool {
        let fileURL = storageURL.appendingPathComponent(key)
        return fileManager.fileExists(atPath: fileURL.path)
    }
}

// MARK: - Transaction Validator

struct TransactionValidator {
    
    enum ValidationError: LocalizedError {
        case invalidAmount
        case insufficientFunds(available: Decimal, requested: Decimal)
        case accountInactive
        case sameAccountTransfer
        case dailyLimitExceeded(limit: Decimal)
        case invalidAccount
        case negativeAmount
        
        var errorDescription: String? {
            switch self {
            case .invalidAmount:
                return "Transaction amount is invalid"
            case .insufficientFunds(let available, let requested):
                return "Insufficient funds. Available: \(available), Requested: \(requested)"
            case .accountInactive:
                return "Account is not active"
            case .sameAccountTransfer:
                return "Cannot transfer to the same account"
            case .dailyLimitExceeded(let limit):
                return "Daily transaction limit of \(limit) exceeded"
            case .invalidAccount:
                return "Account not found"
            case .negativeAmount:
                return "Transaction amount cannot be negative"
            }
        }
    }
    
    static let dailyTransactionLimit: Decimal = 50000.00
    static let minimumTransactionAmount: Decimal = 0.01
    static let maximumTransactionAmount: Decimal = 100000.00
    
    static func validate(transaction: Transaction, sourceAccount: BankAccount,
                         destinationAccount: BankAccount? = nil,
                         dailyTotal: Decimal = 0) -> Result<Void, ValidationError> {
        
        guard transaction.amount > 0 else {
            return .failure(.negativeAmount)
        }
        
        guard transaction.amount >= minimumTransactionAmount,
              transaction.amount <= maximumTransactionAmount else {
            return .failure(.invalidAmount)
        }
        
        guard sourceAccount.isActive else {
            return .failure(.accountInactive)
        }
        
        if transaction.type == .withdrawal || transaction.type == .transfer || transaction.type == .payment {
            guard sourceAccount.balance >= transaction.amount else {
                return .failure(.insufficientFunds(available: sourceAccount.balance, requested: transaction.amount))
            }
        }
        
        if transaction.type == .transfer {
            guard let destAccount = destinationAccount else {
                return .failure(.invalidAccount)
            }
            guard destAccount.id != sourceAccount.id else {
                return .failure(.sameAccountTransfer)
            }
            guard destAccount.isActive else {
                return .failure(.accountInactive)
            }
        }
        
        let projectedDaily = dailyTotal + transaction.amount
        guard projectedDaily <= dailyTransactionLimit else {
            return .failure(.dailyLimitExceeded(limit: dailyTransactionLimit))
        }
        
        return .success(())
    }
}

// MARK: - Transaction Processor

final class TransactionProcessor {
    
    static let shared = TransactionProcessor()
    
    private let secureStorage = SecureStorage.shared
    private let encryption = EncryptionService.shared
    private let transactionQueue = DispatchQueue(label: "com.bankingapp.transactions", attributes: .concurrent)
    
    private let accountsStorageKey = "encrypted_accounts"
    private let transactionsStorageKey = "encrypted_transactions"
    
    private var accounts: [String: BankAccount] = [:]
    private var transactionHistory: [Transaction] = []
    private let lock = NSLock()
    
    private init() {
        loadStoredData()
    }
    
    // MARK: - Data Loading
    
    private func loadStoredData() {
        if let storedAccounts: [String: BankAccount] = try? secureStorage.load(
            forKey: accountsStorageKey, as: [String: BankAccount].self) {
            accounts = storedAccounts
        }
        
        if let storedTransactions: [Transaction] = try? secureStorage.load(
            forKey: transactionsStorageKey, as: [Transaction].self) {
            transactionHistory = storedTransactions
        }
    }
    
    private func persistData() {
        try? secureStorage.save(accounts, forKey: accountsStorageKey)
        try? secureStorage.save(transactionHistory, forKey: transactionsStorageKey)
    }
    
    // MARK: - Account Management
    
    func createAccount(holder: String, type: BankAccount.AccountType,
                       initialBalance: Decimal = 0, currency: Currency = .usd) -> BankAccount {
        lock.lock()
        defer { lock.unlock() }
        
        let accountNumber = generateAccountNumber()
        let account = BankAccount(
            id: UUID().uuidString,
            accountNumber: accountNumber,
            accountHolder: holder,
            balance: initialBalance,
            currency: currency,
            accountType: type,
            isActive: true,
            createdAt: Date(),
            lastActivityAt: Date()
        )
        
        accounts[account.id] = account
        persistData()
        
        return account
    }
    
    func getAccount(id: String) -> BankAccount? {
        lock.lock()
        defer { lock.unlock() }
        return accounts[id]
    }
    
    func getAllAccounts() -> [BankAccount] {
        lock.lock()
        defer { lock.unlock() }
        return Array(accounts.values).sorted { $0.createdAt < $1.createdAt }
    }
    
    func getBalance(accountId: String) -> Decimal? {
        lock.lock()
        defer { lock.unlock() }
        return accounts[accountId]?.balance
    }
    
    private func generateAccountNumber() -> String {
        let prefix = "4200"
        let random = (0..<8).map { _ in String(Int.random(in: 0...9)) }.joined()
        let base = prefix + random
        let checkDigit = luhnCheckDigit(for: base)
        return base + String(checkDigit)
    }
    
    private func luhnCheckDigit(for number: String) -> Int {
        let digits = number.compactMap { $0.wholeNumberValue }
        var sum = 0
        for (index, digit) in digits.reversed().enumerated() {
            if index % 2 == 0 {
                let doubled = digit * 2
                sum += doubled > 9 ? doubled - 9 : doubled
            } else {
                sum += digit
            }
        }
        return (10 - (sum % 10)) % 10
    }
    
    // MARK: - Transaction Processing
    
    func processTransaction(_ transaction: Transaction,
                            completion: @escaping (TransactionResult) -> Void) {
        transactionQueue.async(flags: .barrier) { [weak self] in
            guard let self = self else { return }
            
            self.lock.lock()
            
            guard var sourceAccount = self.accounts[transaction.sourceAccountId] else {
                self.lock.unlock()
                let failedTx = self.failTransaction(transaction, message: "Source account not found")
                DispatchQueue.main.async { completion(failedTx) }
                return
            }
            
            var destinationAccount: BankAccount? = nil
            if let destId = transaction.destinationAccountId {
                destinationAccount = self.accounts[destId]
            }
            
            let dailyTotal = self.calculateDailyTotal(for: transaction.sourceAccountId)
            
            let validationResult = TransactionValidator.validate(
                transaction: transaction,
                sourceAccount: sourceAccount,
                destinationAccount: destinationAccount,
                dailyTotal: dailyTotal
            )
            
            switch validationResult {
            case .failure(let error):
                self.lock.unlock()
                let failedTx = self.failTransaction(transaction, message: error.localizedDescription)
                self.lock.lock()
                self.transactionHistory.append(failedTx.transaction)
                self.persistData()
                self.lock.unlock()
                DispatchQueue.main.async { completion(failedTx) }
                return
                
            case .success:
                break
            }
            
            var completedTransaction = transaction
            
            switch transaction.type {
            case .deposit:
                sourceAccount.balance += transaction.amount
                sourceAccount.lastActivityAt = Date()
                completedTransaction.status = .completed
                
            case .withdrawal:
                sourceAccount.balance -= transaction.amount
                sourceAccount.lastActivityAt = Date()
                completedTransaction.status = .completed
                
            case .transfer:
                guard var destAccount = destinationAccount else {
                    self.lock.unlock()
                    let failedTx = self.failTransaction(transaction, message: "Destination account not found")
                    DispatchQueue.main.async { completion(failedTx) }
                    return
                }
                sourceAccount.balance -= transaction.amount
                destAccount.balance += transaction.amount
                sourceAccount.lastActivityAt = Date()
                destAccount.lastActivityAt = Date()
                self.accounts[destAccount.id] = destAccount
                completedTransaction.status = .completed
                
            case .payment:
                sourceAccount.balance -= transaction.amount
                sourceAccount.lastActivityAt = Date()
                completedTransaction.status = .completed
            }
            
            self.accounts[sourceAccount.id] = sourceAccount
            self.transactionHistory.append(completedTransaction)
            self.persistData()
            
            let result = TransactionResult(
                success: true,
                transaction: completedTransaction,
                message: "Transaction completed successfully",
                updatedBalance: sourceAccount.balance
            )
            
            self.lock.unlock()
            
            self.logTransaction(completedTransaction)
            
            DispatchQueue.main.async { completion(result) }
        }
    }
    
    func processTransactionAsync(_ transaction: Transaction) async -> TransactionResult {
        await withCheckedContinuation { continuation in
            processTransaction(transaction) { result in
                continuation.resume(returning: result)
            }
        }
    }
    
    private func failTransaction(_ transaction: Transaction, message: String) -> TransactionResult {
        var failedTx = transaction
        failedTx.status = .failed
        return TransactionResult(
            success: false,
            transaction: failedTx,
            message: message,
            updatedBalance: nil
        )
    }
    
    private func calculateDailyTotal(for accountId: String) -> Decimal {
        let calendar = Calendar.current
        let startOfDay = calendar.startOfDay(for: Date())
        
        return transactionHistory
            .filter { $0.sourceAccountId == accountId &&
                      $0.status == .completed &&
                      $0.timestamp >= startOfDay &&
                      $0.type != .deposit }
            .reduce(Decimal.zero) { $0 + $1.amount }
    }
    
    // MARK: - Transaction History
    
    func getTransactionHistory(for accountId: String, limit: Int? = nil) -> [Transaction] {
        lock.lock()
        defer { lock.unlock() }
        
        var transactions = transactionHistory
            .filter { $0.sourceAccountId == accountId || $0.destinationAccountId == accountId }
            .sorted { $0.timestamp > $1.timestamp }
        
        if let limit = limit {
            transactions = Array(transactions.prefix(limit))
        }
        
        return transactions
    }
    
    func getAllTransactions(limit: Int? = nil) -> [Transaction] {
        lock.lock()
        defer { lock.unlock() }
        
        let sorted = transactionHistory.sorted { $0.timestamp > $1.timestamp }
        if let limit = limit {
            return Array(sorted.prefix(limit))
        }
        return sorted
    }
    
    func getTransaction(id: UUID) -> Transaction? {
        lock.lock()
        defer { lock.unlock() }
        return transactionHistory.first { $0.id == id }
    }
    
    // MARK: - Audit Logging
    
    private func logTransaction(_ transaction: Transaction) {
        let logEntry = TransactionAuditLog(
            transactionId: transaction.id.uuidString,
            type: transaction.type.rawValue,
            amount: transaction.amount,
            status: transaction.status.rawValue,
            timestamp: transaction.timestamp,
            hash: generateTransactionHash(transaction)
        )
        
        var logs = (try? secureStorage.load(forKey: "audit_logs", as: [TransactionAuditLog].self)) ?? []
        logs.append(logEntry)
        try? secureStorage.save(logs, forKey: "audit_logs")
    }
    
    private func generateTransactionHash(_ transaction: Transaction) -> String {
        let data = "\(transaction.id)\(transaction.amount)\(transaction.timestamp)\(transaction.referenceNumber)"
        guard let inputData = data.data(using: .utf8) else { return "" }
        return encryption.hashData(inputData)
    }
}

struct TransactionAuditLog: Codable {
    let transactionId: String
    let type: String
    let amount: Decimal
    let status: String
    let timestamp: Date
    let hash: String
}

// MARK: - Banking View Model

final class BankingViewModel: ObservableObject {
    
    @Published var accounts: [BankAccount] = []
    @Published var selectedAccount: BankAccount?
    @Published var transactions: [Transaction] = []
    @Published var isProcessing = false
    @Published var alertMessage: String?
    @Published var showAlert = false
    @Published var totalBalance: Decimal = 0
    
    private let processor = TransactionProcessor.shared
    
    init() {
        refreshData()
    }
    
    func refreshData() {
        accounts = processor.getAllAccounts()
        totalBalance = accounts.reduce(Decimal.zero) { $0 + $1.balance }
        
        if let selected = selectedAccount {
            transactions = processor.getTransactionHistory(for: selected.id, limit: 50)
            selectedAccount = processor.getAccount(id: selected.id)
        } else {
            transactions = processor.getAllTransactions(limit: 50)
        }
    }
    
    func createAccount(holder: String, type: BankAccount.AccountType,
                       initialBalance: Decimal) {
        let account = processor.createAccount(
            holder: holder, type: type, initialBalance: initialBalance
        )
        selectedAccount = account
        refreshData()
        showAlertMessage("Account created: \(account.maskedAccountNumber)")
    }
    
    func selectAccount(_ account: BankAccount) {
        selectedAccount = account
        transactions = processor.getTransactionHistory(for: account.id, limit: 50)
    }
    
    func deposit(amount: Decimal, description: String) {
        guard let account = selectedAccount else {
            showAlertMessage("Please select an account")
            return
        }
        
        let transaction = Transaction(
            type: .deposit,
            amount: amount,
            sourceAccountId: account.id,
            description: description
        )
        
        executeTransaction(transaction)
    }
    
    func withdraw(amount: Decimal, description: String) {
        guard let account = selectedAccount else {
            showAlertMessage("Please select an account")
            return
        }
        
        let transaction = Transaction(
            type: .withdrawal,
            amount: amount,
            sourceAccountId: account.id,
            description: description
        )
        
        executeTransaction(transaction)
    }
    
    func transfer(amount: Decimal, toAccountId: String, description: String) {
        guard let account = selectedAccount else {
            showAlertMessage("Please select a source account")
            return
        }
        
        let transaction = Transaction(
            type: .transfer,
            amount: amount,
            sourceAccountId: account.id,
            destinationAccountId: toAccountId,
            description: description
        )
        
        executeTransaction(transaction)
    }
    
    func makePayment(amount: Decimal, description: String) {
        guard let account = selectedAccount else {
            showAlertMessage("Please select an account")
            return
        }
        
        let transaction = Transaction(
            type: .payment,
            amount: amount,
            sourceAccountId: account.id,
            description: description
        )
        
        executeTransaction(transaction)
    }
    
    private func executeTransaction(_ transaction: Transaction) {
        isProcessing = true
        
        processor.processTransaction(transaction) { [weak self] result in
            guard let self = self else { return }
            self.isProcessing = false
            self.showAlertMessage(result.message)
            self.refreshData()
        }
    }
    
    private func showAlertMessage(_ message: String) {
        alertMessage = message
        showAlert = true
    }
}

