struct QuickActionButton: View {
    let type: TransactionType
    let action: () -> Void
    
    var body: some View {
        Button(action: action) {
            VStack(spacing: 8) {
                Image(systemName: iconName)
                    .font(.title2)
                    .foregroundColor(.blue)
                Text(type.rawValue)
                    .font(.caption2)
                    .foregroundColor(.primary)
            }
            .frame(maxWidth: .infinity)
            .padding(.vertical, 12)
            .background(
                RoundedRectangle(cornerRadius: 12)
                    .fill(Color(.tertiarySystemBackground))
            )
        }
    }
    
    private var iconName: String {
        switch type {
        case .deposit: return "arrow.down.circle.fill"
        case .withdrawal: return "arrow.up.circle.fill"
        case .transfer: return "arrow.left.arrow.right.circle.fill"
        case .payment: return "creditcard.fill"
        }
    }
}

struct TransactionRowView: View {
    let transaction: Transaction
    
    var body: some View {
        HStack(spacing: 12) {
            Circle()
                .fill(statusColor)
                .frame(width: 10, height: 10)
            
            VStack(alignment: .leading, spacing: 2) {
                Text(transaction.description)
                    .font(.subheadline)
                    .fontWeight(.medium)
                    .lineLimit(1)
                HStack {
                    Text(transaction.type.rawValue)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Text("•")
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Text(transaction.timestamp, style: .relative)
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            
            Spacer()
            
            VStack(alignment: .trailing, spacing: 2) {
                Text(amountText)
                    .font(.subheadline)
                    .fontWeight(.semibold)
                    .foregroundColor(amountColor)
                Text(transaction.status.rawValue)
                    .font(.caption2)
                    .foregroundColor(statusColor)
            }
        }
        .padding(.vertical, 8)
        .padding(.horizontal, 12)
        .background(
            RoundedRectangle(cornerRadius: 8)
                .fill(Color(.systemBackground))
        )
    }
    
    private var amountText: String {
        let prefix = transaction.type == .deposit ? "+" : "-"
        return "\(prefix)\(formatCurrency(transaction.amount))"
    }
    
    private var amountColor: Color {
        transaction.type == .deposit ? .green : .red
    }
    
    private var statusColor: Color {
        switch transaction.status {
        case .completed: return .green
        case .pending: return .orange
        case .failed: return .red
        case .cancelled: return .gray
        }
    }
}

struct TransactionFormView: View {
    @ObservedObject var viewModel: BankingViewModel
    let transactionType: TransactionType
    @Environment(\.dismiss) var dismiss
    
    @State private var amountText = ""
    @State private var description = ""
    @State private var destinationAccountId = ""
    
    var body: some View {
        NavigationView {
            Form {
                Section("Transaction Details") {
                    HStack {
                        Text("Type")
                        Spacer()
                        Text(transactionType.rawValue)
                            .foregroundColor(.secondary)
                    }
                    
                    if let account = viewModel.selectedAccount {
                        HStack {
                            Text("Account")
                            Spacer()
                            Text(account.maskedAccountNumber)
                                .foregroundColor(.secondary)
                        }
                        
                        HStack {
                            Text("Available")
                            Spacer()
                            Text(formatCurrency(account.balance))
                                .foregroundColor(.secondary)
                        }
                    }
                }
                
                Section("Amount") {
                    TextField("Enter amount", text: $amountText)
                        .keyboardType(.decimalPad)
                }
                
                if transactionType == .transfer {
                    Section("Destination") {
                        Picker("To Account", selection: $destinationAccountId) {
                            Text("Select Account").tag("")
                            ForEach(viewModel.accounts.filter { $0.id != viewModel.selectedAccount?.id }) { account in
                                Text("\(account.accountHolder) - \(account.maskedAccountNumber)")
                                    .tag(account.id)
                            }
                        }
                    }
                }
                
                Section("Description") {
                    TextField("Enter description", text: $description)
                }
                
                Section {
                    Button(action: submitTransaction) {
                        HStack {
                            Spacer()
                            Text("Submit \(transactionType.rawValue)")
                                .fontWeight(.semibold)
                            Spacer()
                        }
                    }
                    .disabled(!isFormValid)
                }
            }
            .navigationTitle("New \(transactionType.rawValue)")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
    
    private var isFormValid: Bool {
        guard let amount = Decimal(string: amountText), amount > 0 else { return false }
        guard !description.isEmpty else { return false }
        if transactionType == .transfer && destinationAccountId.isEmpty { return false }
        return true
    }
    
    private func submitTransaction() {
        guard let amount = Decimal(string: amountText) else { return }
        
        switch transactionType {
        case .deposit:
            viewModel.deposit(amount: amount, description: description)
        case .withdrawal:
            viewModel.withdraw(amount: amount, description: description)
        case .transfer:
            viewModel.transfer(amount: amount, toAccountId: destinationAccountId, description: description)
        case .payment:
            viewModel.makePayment(amount: amount, description: description)
        }
        
        dismiss()
    }
}

struct CreateAccountView: View {
    @ObservedObject var viewModel: BankingViewModel
    @Environment(\.dismiss) var dismiss
    
    @State private var holderName = ""
    @State private var accountType: BankAccount.AccountType = .checking
    @State private var initialBalanceText = "0"
    
    var body: some View {
        NavigationView {
            Form {
                Section("Account Holder") {
                    TextField("Full Name", text: $holderName)
                        .textContentType(.name)
                        .autocapitalization(.words)
                }
                
                Section("Account Type") {
                    Picker("Type", selection: $accountType) {
                        Text("Checking").tag(BankAccount.AccountType.checking)
                        Text("Savings").tag(BankAccount.AccountType.savings)
                        Text("Investment").tag(BankAccount.AccountType.investment)
                    }
                    .pickerStyle(.segmented)
                }
                
                Section("Initial Deposit") {
                    TextField("Amount", text: $initialBalanceText)
                        .keyboardType(.decimalPad)
                }
                
                Section {
                    Button(action: createAccount) {
                        HStack {
                            Spacer()
                            Text("Create Account")
                                .fontWeight(.semibold)
                            Spacer()
                        }
                    }
                    .disabled(holderName.trimmingCharacters(in: .whitespaces).isEmpty)
                }
            }
            .navigationTitle("New Account")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") { dismiss() }
                }
            }
        }
    }
    
    private func createAccount() {
        let balance = Decimal(string: initialBalanceText) ?? 0
        viewModel.createAccount(
            holder: holderName.trimmingCharacters(in: .whitespaces),
            type: accountType,
            initialBalance: max(0, balance)
        )
        dismiss()
    }
}

// MARK: - Helper

func formatCurrency(_ amount: Decimal) -> String {
    let formatter = NumberFormatter()
    formatter.numberStyle = .currency
    formatter.currencyCode = "USD"
    formatter.minimumFractionDigits = 2
    formatter.maximumFractionDigits = 2
    return formatter.string(from: amount as NSDecimalNumber) ?? "$0.00"
}

